import{_ as t,c as a,o,a4 as r}from"./chunks/framework.I1cCAST3.js";const e="/assets/hosts.K17OJ_F3.png",m=JSON.parse('{"title":"主机列表操作","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/index.md","filePath":"docs/hosts/index.md"}'),s={name:"docs/hosts/index.md"},l=r('<h1 id="主机列表操作" tabindex="-1">主机列表操作 <a class="header-anchor" href="#主机列表操作" aria-label="Permalink to &quot;主机列表操作&quot;">​</a></h1><p>主机列表是您集中浏览、搜索和管理所有已添加服务器的控制面板，帮助您在几秒内连接到任意主机。</p><p><img src="'+e+'" alt=""></p><h2 id="打开主机列表" tabindex="-1">打开主机列表 <a class="header-anchor" href="#打开主机列表" aria-label="Permalink to &quot;打开主机列表&quot;">​</a></h2><p>打开左侧边栏并点击 <strong>Hosts</strong>。主机列表提供两种视图：</p><ul><li><strong>直接连接</strong> -- 通过网络直接连接的主机，无需中间跳转。</li><li><strong>堡垒机资源</strong> -- 仅可通过堡垒机（跳板服务器）访问的主机。点击 <strong>堡垒机资源</strong> 标签切换到此视图。</li></ul><h2 id="搜索与过滤" tabindex="-1">搜索与过滤 <a class="header-anchor" href="#搜索与过滤" aria-label="Permalink to &quot;搜索与过滤&quot;">​</a></h2><ol><li>点击主机列表顶部的 <strong>搜索框</strong>。</li><li>输入 IP 地址、主机名或别名。</li><li>查看实时过滤的搜索结果。</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>结合搜索与堡垒机资源视图，可将结果缩小到特定的访问路径。</p></div><h2 id="收藏功能" tabindex="-1">收藏功能 <a class="header-anchor" href="#收藏功能" aria-label="Permalink to &quot;收藏功能&quot;">​</a></h2><ol><li>右键点击主机以打开右键菜单。</li><li>选择 <strong>添加到收藏夹</strong> 将主机固定到收藏列表。</li><li>要取消固定，再次右键点击主机并选择 <strong>从收藏夹移除</strong>。</li></ol><p>收藏的主机会显示在列表顶部，让您一键访问最常用的服务器。</p><h2 id="右键菜单操作" tabindex="-1">右键菜单操作 <a class="header-anchor" href="#右键菜单操作" aria-label="Permalink to &quot;右键菜单操作&quot;">​</a></h2><p>右键点击任意主机可查看可用操作：</p><table tabindex="0"><thead><tr><th>操作</th><th>描述</th></tr></thead><tbody><tr><td><strong>连接</strong></td><td>打开到该主机的 SSH 会话。</td></tr><tr><td><strong>编辑</strong></td><td>修改主机的连接设置。</td></tr><tr><td><strong>克隆</strong></td><td>以新名称复制主机条目。</td></tr><tr><td><strong>删除</strong></td><td>从 Chaterm 中永久删除该主机。</td></tr><tr><td><strong>添加到收藏夹</strong></td><td>将主机固定到列表顶部。</td></tr><tr><td><strong>从收藏夹移除</strong></td><td>取消主机的收藏固定。</td></tr></tbody></table><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><ul><li><strong>按用途分组</strong> -- 将主机组织到 <code>生产环境</code>、<code>测试环境</code>、<code>开发环境</code> 或 <code>数据库服务器</code> 等分组中，使列表易于管理。</li><li><strong>使用 SSH 密钥</strong> -- 优先使用密钥认证而非密码认证。详见 <a href="/docs/manage/keys/">密钥管理</a> 了解设置方法。</li><li><strong>添加清晰备注</strong> -- 记录重要细节（环境、负责人、特殊端口），以便团队成员一目了然地了解主机信息。</li><li><strong>定期清理</strong> -- 定期检查列表，删除已停用或不再使用的主机。</li></ul><h2 id="相关页面" tabindex="-1">相关页面 <a class="header-anchor" href="#相关页面" aria-label="Permalink to &quot;相关页面&quot;">​</a></h2><ul><li><a href="./add-personal">添加个人主机</a> -- 添加通过网络直接连接的主机。</li><li><a href="./add-bastion">添加堡垒机</a> -- 添加通过堡垒机服务器访问的主机。</li><li><a href="./add-router">添加路由器</a> -- 配置路由器或跳转主机条目。</li><li><a href="./connect">连接到主机</a> -- 建立 SSH 会话并使用终端。</li><li><a href="./edit-clone-delete">编辑、克隆或删除主机</a> -- 修改或删除现有主机条目。</li><li><a href="./import-export">导入和导出主机</a> -- 批量导入或导出主机列表。</li></ul>',19),i=[l];function d(n,h,c,g,p,_){return o(),a("div",null,i)}const b=t(s,[["render",d]]);export{m as __pageData,b as default};
